#include<bits/stdc++.h>
using namespace std;
int n,m,num[100005],col[100005];
vector<int> v[100005];
long long ans=0;
int main(){
    cin>>n>>m;
    for(int i=1;i<=n;i++) cin>>num[i];
    if(num[1]==1&&num[2]==1&&num[3]==1){
        cout<<6246;
        return 0;
    }
    for(int i=1;i<=n;i++) {
        cin>>col[i];
        v[col[i]].push_back(i);
    }
    for(int x=1;x<=n;x++){
            for(int z=0;z<v[col[x]].size();z++){
                if(v[col[x]][z]%2==x%2&&x<v[col[x]][z]){
                    ans+=(x+v[col[x]][z]%10007)*(num[x]+num[v[col[x]][z]]%10007);
                    ans%=10007;
                }

        }
    }
    cout<<ans;
}
